-- 章节数据 - 魔幻传说：龙之守护者（英文版）
-- ============================================

INSERT INTO chapters (chapter_id, book_id, title, content, selected_cards, order_num) VALUES
('chapter-fan006-01-en', 'preset-fantasy-006-en', 'The Mysterious Mark',
'Drake was an ordinary boy until one day, a strange dragon-shaped mark appeared on his arm. The mark glowed faintly, as if containing some mysterious power. He tried to hide it, but it grew more visible. An elder in the village saw the mark and his expression changed dramatically: "This is the Dragon Blood Mark! You are a descendant of the dragons!" Drake was shocked. He never imagined he had any connection to the legendary dragon race. The elder told him this mark meant he carried an important destiny.',
'{"weather":{"name":"Dragon Breath Cloud","icon":"☁️","description":"Cloud of dragon essence"},"terrain":{"name":"Village","icon":"🏘️","description":"Peaceful village"},"adventure":{"name":"Awaken Power","icon":"💫","description":"Awaken dragon blood"},"equipment":{"name":"Dragon Mark","icon":"🔰","description":"Proof of dragon blood"}}',
1),

('chapter-fan006-02-en', 'preset-fantasy-006-en', 'The Dragon Legend',
'Drake went to the village ancient library to research dragon records. The librarian, a kind old man, brought out a yellowed ancient book recording dragon history. Dragons were once guardians of this continent, living in peace with humans, protecting the world balance. But a thousand years ago, a great war nearly wiped them out. Only a few dragon descendants hid among humans. The old man said: "The mark on your arm is the last hope of the dragon race."',
'{"weather":{"name":"Divine Light","icon":"✨","description":"Dragon blessing light"},"terrain":{"name":"Ancient Ruins","icon":"🏛️","description":"Witness of dragon history"},"adventure":{"name":"Awaken Power","icon":"💫","description":"Awaken dragon blood"},"equipment":{"name":"Ancient Scroll","icon":"📜","description":"Records dragon secrets"}}',
2),

('chapter-fan006-03-en', 'preset-fantasy-006-en', 'The Dragon Egg Secret',
'Guided by the ancient book, Drake came to a hidden cave. Deep inside, he found a dragon egg glowing with golden light. This was the last dragon egg in the world, containing hope for dragon revival. When Drake approached, his mark began to glow, resonating with the egg. Ella the Elf emerged from the shadows: "You have finally come, dragon descendant. I have guarded this egg for a long time. Now it is your responsibility." Drake solemnly took the egg, feeling its warmth.',
'{"weather":{"name":"Fire Storm","icon":"🔥","description":"Storm from dragon flame"},"terrain":{"name":"Hidden Cave","icon":"🕳️","description":"Dragon egg hiding place"},"adventure":{"name":"Guard Dragon Egg","icon":"🥚","description":"Protect the last egg"},"equipment":{"name":"Magic Shield","icon":"🛡️","description":"Dragon protection"}}',
3),

('chapter-fan006-04-en', 'preset-fantasy-006-en', 'Dark Forces Pursue',
'When Drake left the cave with the egg, the sky turned dark. A dark aura enveloped the forest—evil forces tracking the egg. Ella said: "Dark forces have been seeking the egg. They want to destroy the last hope of dragons." Drake held the egg tight and fled through the forest. Dark creatures surged from all directions, but Drake mark glowed, repelling nearby enemies. He knew he must protect this egg.',
'{"weather":{"name":"Darkness Falls","icon":"🌑","description":"Evil force darkness"},"terrain":{"name":"Elf Forest","icon":"🌳","description":"Elven homeland"},"adventure":{"name":"Battle Darkness","icon":"⚔️","description":"Fight evil forces"},"equipment":{"name":"Dragon Mark","icon":"🔰","description":"Proof of dragon blood"}}',
4),

('chapter-fan006-05-en', 'preset-fantasy-006-en', 'Dragon Sanctuary',
'Led by Ella, Drake arrived at the Dragon Sanctuary. This was where dragons once lived. Though abandoned for ages, dragon power still lingered. In the center stood an ancient altar with dragon prophecies carved upon it. Ella said: "According to prophecy, when a dragon descendant awakens, the egg will hatch and dragons will rise again." Drake looked at the altar inscriptions, feeling the call in his blood.',
'{"weather":{"name":"Divine Light","icon":"✨","description":"Dragon blessing light"},"terrain":{"name":"Dragon Sanctuary","icon":"🏔️","description":"Dragon homeland"},"adventure":{"name":"Awaken Power","icon":"💫","description":"Awaken dragon blood"},"equipment":{"name":"Dragon Crystal","icon":"💎","description":"Contains dragon power"}}',
5),

('chapter-fan006-06-en', 'preset-fantasy-006-en', 'Awakening Ritual',
'Drake performed the awakening ritual at the sanctuary. Standing on the altar, he placed the egg in the center. As ancient incantations sounded, his mark began to shine brilliantly. A powerful force surged from within him—the power of dragon blood. Drake felt his body changing. His eyes became sharp like a dragon, his strength greatly enhanced. After the ritual, the Dragon Elder voice echoed: "You have awakened, young dragon descendant."',
'{"weather":{"name":"Fire Storm","icon":"🔥","description":"Storm from dragon flame"},"terrain":{"name":"Dragon Sanctuary","icon":"🏔️","description":"Dragon homeland"},"adventure":{"name":"Awaken Power","icon":"💫","description":"Awaken dragon blood"},"equipment":{"name":"Dragon Crystal","icon":"💎","description":"Contains dragon power"}}',
6),

('chapter-fan006-07-en', 'preset-fantasy-006-en', 'Elven Aid',
'After awakening, Drake power increased greatly, but he needed to learn control. Ella invited him to the elven village. The Elven Elder said: "Dragons and elves are ancient allies. We will help you fulfill your destiny." In the village, Drake learned magic and combat skills. The elves also crafted a magic shield to protect him in battle.',
'{"weather":{"name":"Dragon Breath Cloud","icon":"☁️","description":"Cloud of dragon essence"},"terrain":{"name":"Elf Forest","icon":"🌳","description":"Elven homeland"},"adventure":{"name":"Battle Darkness","icon":"⚔️","description":"Fight evil forces"},"equipment":{"name":"Magic Shield","icon":"🛡️","description":"Dragon protection"}}',
7),

('chapter-fan006-08-en', 'preset-fantasy-006-en', 'Final Battle',
'Dark forces finally found the Dragon Sanctuary. The Dark Lord led an army to surround it, wanting to destroy the egg and eliminate dragons forever. Drake stood at the entrance, ready for the final battle. Ella and elven warriors stood beside him against the dark army. The battle was fierce. Drake unleashed his full dragon blood power, facing the Dark Lord directly. At the crucial moment, the egg suddenly emitted intense light.',
'{"weather":{"name":"Darkness Falls","icon":"🌑","description":"Evil force darkness"},"terrain":{"name":"Dark Castle","icon":"🏰","description":"Evil force lair"},"adventure":{"name":"Battle Darkness","icon":"⚔️","description":"Fight evil forces"},"equipment":{"name":"Dragon Mark","icon":"🔰","description":"Proof of dragon blood"}}',
8),

('chapter-fan006-09-en', 'preset-fantasy-006-en', 'Dragon Birth',
'At the battle peak, the egg began to crack. Golden light shot from the fissures, illuminating the entire battlefield. A baby dragon emerged, letting out a mighty roar that repelled all dark creatures. The dragon flew to Drake side, resonating with his mark. Drake felt unprecedented power. He merged with the dragon, transforming into a massive golden dragon. The Dark Lord retreated under the dragon might and was finally destroyed.',
'{"weather":{"name":"Divine Light","icon":"✨","description":"Dragon blessing light"},"terrain":{"name":"Dragon Sanctuary","icon":"🏔️","description":"Dragon homeland"},"adventure":{"name":"Dragon Birth","icon":"🐉","description":"Baby dragon hatches"},"equipment":{"name":"Dragon Crystal","icon":"💎","description":"Contains dragon power"}}',
9),

('chapter-fan006-10-en', 'preset-fantasy-006-en', 'New Guardian',
'After the dark forces were destroyed, peace returned to the Dragon Sanctuary. The baby dragon had grown into a majestic dragon, choosing Drake as its partner. The Dragon Elder voice echoed again: "Drake, you have fulfilled your destiny. Now you are the new Dragon Guardian. Protect this continent, protect the dragon legacy." Drake looked at the dragon beside him, filled with responsibility. He knew this was just the beginning of his journey as Dragon Guardian.',
'{"weather":{"name":"Dragon Breath Cloud","icon":"☁️","description":"Cloud of dragon essence"},"terrain":{"name":"Dragon Sanctuary","icon":"🏔️","description":"Dragon homeland"},"adventure":{"name":"Guard Dragon Egg","icon":"🥚","description":"Protect the last egg"},"equipment":{"name":"Ancient Scroll","icon":"📜","description":"Records dragon secrets"}}',
10);

-- ============================================
-- 章节数据 - 都市言情：跨越时空的爱（中文版）
-- ============================================

INSERT INTO chapters (chapter_id, book_id, title, content, selected_cards, order_num) VALUES
('chapter-rom006-01', 'preset-romance-006', '意外的相遇',
'林晓雨是一名自由撰稿人，正在咖啡馆里写作。她喜欢这里的氛围，安静而温馨。就在她专注于笔记本时，一个温和的声音响起："这个位置有人吗？"她抬起头，看到一个穿着休闲西装的男人，手里拿着一杯咖啡。那是陈远航，一名建筑师，刚刚完成了一个重要项目，想找个地方休息。两人就这样意外地相遇了，谁也没想到这次偶遇会改变他们的人生。',
'{"weather":{"name":"阳光明媚","icon":"☀️","description":"温暖的阳光"},"terrain":{"name":"咖啡馆","icon":"☕","description":"温馨的咖啡馆"},"adventure":{"name":"邂逅","icon":"💫","description":"命运的相遇"},"equipment":{"name":"笔记本","icon":"📓","description":"记录故事"}}',
1),

('chapter-rom006-02', 'preset-romance-006', '美好的一天',
'陈远航坐下来后，两人开始聊天。晓雨发现远航不仅是一位优秀的建筑师，还是一个有趣的人。他们聊了很多话题，从建筑到文学，从旅行到美食。时间过得很快，当他们意识到时，已经是傍晚了。远航提议一起去附近的公园散步，晓雨欣然同意。夕阳下，两人并肩走在公园的小路上，聊着各自的梦想和生活。',
'{"weather":{"name":"夕阳西下","icon":"🌇","description":"浪漫的黄昏"},"terrain":{"name":"城市街头","icon":"🏙️","description":"繁忙的城市"},"adventure":{"name":"邂逅","icon":"💫","description":"命运的相遇"},"equipment":{"name":"手机","icon":"📱","description":"联系的工具"}}',
2),

('chapter-rom006-03', 'preset-romance-006', '告别与约定',
'傍晚时分，远航必须离开了。他明天要飞往另一个城市，开始一个新的项目。在分别前，他们交换了联系方式。远航说："等我回来，我们再见面。"晓雨点点头，心中有些不舍。她看着远航离去的背影，心中涌起一种奇妙的感觉。她不知道这是不是爱情，但她知道，她想再见到他。那天晚上，晓雨在笔记本上写下了今天的经历。',
'{"weather":{"name":"星空璀璨","icon":"⭐","description":"美丽的夜空"},"terrain":{"name":"机场","icon":"✈️","description":"离别与重逢"},"adventure":{"name":"邂逅","icon":"💫","description":"命运的相遇"},"equipment":{"name":"手机","icon":"📱","description":"联系的工具"}}',
3),

('chapter-rom006-04', 'preset-romance-006', '远距离的思念',
'远航离开后的日子里，晓雨每天都在想念他。他们通过视频通话保持联系，分享彼此的生活。晓雨发现，自己越来越期待每天的通话时间。远航也表达了同样的感受，他说每次看到晓雨的笑容，疲惫就会消失。虽然相隔两地，但他们的心越来越近。晓雨开始相信，这就是人们常说的缘分。',
'{"weather":{"name":"细雨绵绵","icon":"🌧️","description":"浪漫的雨天"},"terrain":{"name":"城市街头","icon":"🏙️","description":"繁忙的城市"},"adventure":{"name":"坚持","icon":"💪","description":"为爱坚持"},"equipment":{"name":"手机","icon":"📱","description":"联系的工具"}}',
4),

('chapter-rom006-05', 'preset-romance-006', '意外的访客',
'一个月后，晓雨正在咖啡馆写作，突然看到一个熟悉的身影。是远航！他提前完成了项目，想给晓雨一个惊喜。晓雨惊喜地站起来，两人紧紧拥抱在一起。远航说："我忍不住想见你，所以提前回来了。"晓雨感动得眼眶湿润。他们决定好好珍惜在一起的时光，一起去看电影、吃饭、散步。',
'{"weather":{"name":"阳光明媚","icon":"☀️","description":"温暖的阳光"},"terrain":{"name":"咖啡馆","icon":"☕","description":"温馨的咖啡馆"},"adventure":{"name":"邂逅","icon":"💫","description":"命运的相遇"},"equipment":{"name":"相机","icon":"📷","description":"记录美好"}}',
5),

('chapter-rom006-06', 'preset-romance-006', '现实的考验',
'随着相处加深，他们开始讨论未来。远航的工作需要经常出差，而晓雨喜欢自由的生活方式。他们面临着一个选择：是继续异地恋，还是其中一人做出改变？晓雨的妈妈也知道了这段关系，她担心远航的工作不稳定，会影响晓雨的生活。晓雨和远航坦诚地交流了各自的担忧，决定一起面对这些挑战。',
'{"weather":{"name":"阴天","icon":"☁️","description":"阴沉的天空"},"terrain":{"name":"城市街头","icon":"🏙️","description":"繁忙的城市"},"adventure":{"name":"坚持","icon":"💪","description":"为爱坚持"},"equipment":{"name":"手机","icon":"📱","description":"联系的工具"}}',
6),

('chapter-rom006-07', 'preset-romance-006', '勇敢的决定',
'经过深思熟虑，远航做出了一个重要的决定。他申请调回晓雨所在的城市，这样他们就可以在一起了。晓雨感动于远航的付出，她也决定更加努力地写作，实现自己的梦想。远航说："我想和你一起创造未来。"晓雨紧紧握住他的手，说："我也是。"他们决定一起面对未来的挑战。',
'{"weather":{"name":"夕阳西下","icon":"🌇","description":"浪漫的黄昏"},"terrain":{"name":"咖啡馆","icon":"☕","description":"温馨的咖啡馆"},"adventure":{"name":"坚持","icon":"💪","description":"为爱坚持"},"equipment":{"name":"笔记本","icon":"📓","description":"记录故事"}}',
7),

('chapter-rom006-08', 'preset-romance-006', '家人的理解',
'晓雨带着远航回家见父母。起初，晓雨的妈妈有些担心，但在和远航深入交谈后，她看到了远航的真诚和责任感。远航向晓雨的父母表达了他对晓雨的爱和对未来的规划。晓雨的妈妈终于放心了，她说："只要你们幸福，我们就支持。"晓雨感动地拥抱了妈妈，感谢她的理解。',
'{"weather":{"name":"阳光明媚","icon":"☀️","description":"温暖的阳光"},"terrain":{"name":"家中","icon":"🏠","description":"温馨的家"},"adventure":{"name":"坚持","icon":"💪","description":"为爱坚持"},"equipment":{"name":"相机","icon":"📷","description":"记录美好"}}',
8),

('chapter-rom006-09', 'preset-romance-006', '浪漫的求婚',
'一年后，远航带着晓雨来到了他们第一次相遇的咖啡馆。咖啡馆里布置满了鲜花和蜡烛，温馨而浪漫。远航单膝跪地，拿出一枚戒指，说："晓雨，从我们相遇的那一刻起，我就知道你是我想要共度一生的人。你愿意嫁给我吗？"晓雨感动得泪流满面，点头说："我愿意。"周围的顾客都为他们鼓掌祝福。',
'{"weather":{"name":"星空璀璨","icon":"⭐","description":"美丽的夜空"},"terrain":{"name":"咖啡馆","icon":"☕","description":"温馨的咖啡馆"},"adventure":{"name":"求婚","icon":"💍","description":"浪漫的求婚"},"equipment":{"name":"戒指","icon":"💍","description":"爱情的象征"}}',
9),

('chapter-rom006-10', 'preset-romance-006', '幸福的结局',
'婚礼在海边举行，阳光明媚，海风轻拂。晓雨穿着白色婚纱，美丽动人。远航站在她面前，眼中满是爱意。他们在亲友的见证下交换了誓言，承诺永远相爱。晓雨的妈妈在一旁擦着眼泪，为女儿感到幸福。婚礼结束后，他们手牵手走在海边，看着夕阳西下。晓雨说："谢谢你，让我相信爱情。"远航笑着说："谢谢你，让我找到了家。"',
'{"weather":{"name":"夕阳西下","icon":"🌇","description":"浪漫的黄昏"},"terrain":{"name":"海边","icon":"🏖️","description":"浪漫的海边"},"adventure":{"name":"求婚","icon":"💍","description":"浪漫的求婚"},"equipment":{"name":"戒指","icon":"💍","description":"爱情的象征"}}',
10);

