INSERT INTO chapters (chapter_id, book_id, title, content, selected_cards, order_num) VALUES
('chapter-rom006-01-en', 'preset-romance-006-en', 'Unexpected Encounter',
'Luna was a freelance writer, working in her favorite cafe. She loved the quiet, cozy atmosphere. As she focused on her notebook, a warm voice asked: "Is this seat taken?" She looked up to see a man in casual business attire, holding a coffee. This was Atlas, an architect who had just finished an important project and wanted a place to relax. They met unexpectedly, neither knowing this encounter would change their lives.',
'{"weather":{"name":"Sunny Day","icon":"☀️","description":"Warm sunshine"},"terrain":{"name":"Cafe","icon":"☕","description":"Cozy cafe"},"adventure":{"name":"Encounter","icon":"💫","description":"Fateful meeting"},"equipment":{"name":"Notebook","icon":"📓","description":"Record stories"}}',
1),

('chapter-rom006-02-en', 'preset-romance-006-en', 'A Beautiful Day',
'After Atlas sat down, they began chatting. Luna discovered he was not only a talented architect but also an interesting person. They talked about many topics—from architecture to literature, from travel to food. Time flew by, and when they noticed, it was already evening. Atlas suggested a walk in the nearby park, and Luna happily agreed. Under the sunset, they walked side by side on the park path, sharing their dreams and lives.',
'{"weather":{"name":"Sunset","icon":"🌇","description":"Romantic dusk"},"terrain":{"name":"City Street","icon":"🏙️","description":"Busy city"},"adventure":{"name":"Encounter","icon":"💫","description":"Fateful meeting"},"equipment":{"name":"Phone","icon":"📱","description":"Communication tool"}}',
2),

('chapter-rom006-03-en', 'preset-romance-006-en', 'Farewell and Promise',
'As evening came, Atlas had to leave. He was flying to another city tomorrow for a new project. Before parting, they exchanged contact information. Atlas said: "When I return, let us meet again." Luna nodded, feeling a bit reluctant. She watched him walk away, a strange feeling rising in her heart. She did not know if it was love, but she knew she wanted to see him again. That night, Luna wrote about the day in her notebook.',
'{"weather":{"name":"Starry Night","icon":"⭐","description":"Beautiful night sky"},"terrain":{"name":"Airport","icon":"✈️","description":"Farewell and reunion"},"adventure":{"name":"Encounter","icon":"💫","description":"Fateful meeting"},"equipment":{"name":"Phone","icon":"📱","description":"Communication tool"}}',
3),

('chapter-rom006-04-en', 'preset-romance-006-en', 'Long Distance Yearning',
'In the days after Atlas left, Luna thought about him every day. They kept in touch through video calls, sharing their lives. Luna found herself looking forward to their daily conversations more and more. Atlas expressed the same feelings—he said seeing Luna smile made his fatigue disappear. Though separated by distance, their hearts grew closer. Luna began to believe this was what people called fate.',
'{"weather":{"name":"Light Rain","icon":"🌧️","description":"Romantic rainy day"},"terrain":{"name":"City Street","icon":"🏙️","description":"Busy city"},"adventure":{"name":"Persistence","icon":"💪","description":"Fight for love"},"equipment":{"name":"Phone","icon":"📱","description":"Communication tool"}}',
4),

('chapter-rom006-05-en', 'preset-romance-006-en', 'Unexpected Visitor',
'A month later, Luna was writing in the cafe when she saw a familiar figure. It was Atlas! He had finished his project early and wanted to surprise her. Luna stood up in delight, and they embraced tightly. Atlas said: "I could not wait to see you, so I came back early." Luna was moved to tears. They decided to cherish their time together—watching movies, dining out, taking walks.',
'{"weather":{"name":"Sunny Day","icon":"☀️","description":"Warm sunshine"},"terrain":{"name":"Cafe","icon":"☕","description":"Cozy cafe"},"adventure":{"name":"Encounter","icon":"💫","description":"Fateful meeting"},"equipment":{"name":"Camera","icon":"📷","description":"Capture moments"}}',
5),

('chapter-rom006-06-en', 'preset-romance-006-en', 'Reality Test',
'As they grew closer, they began discussing the future. Atlas work required frequent travel, while Luna loved her free lifestyle. They faced a choice: continue long-distance, or have one person make a change? Luna mom also learned about the relationship and worried Atlas unstable work might affect Luna life. Luna and Atlas honestly shared their concerns and decided to face these challenges together.',
'{"weather":{"name":"Cloudy","icon":"☁️","description":"Overcast sky"},"terrain":{"name":"City Street","icon":"🏙️","description":"Busy city"},"adventure":{"name":"Persistence","icon":"💪","description":"Fight for love"},"equipment":{"name":"Phone","icon":"📱","description":"Communication tool"}}',
6),

('chapter-rom006-07-en', 'preset-romance-006-en', 'Brave Decision',
'After careful consideration, Atlas made an important decision. He applied to transfer back to Luna city so they could be together. Luna was moved by his sacrifice and decided to work harder on her writing to achieve her dreams. Atlas said: "I want to create a future with you." Luna squeezed his hand: "Me too." They decided to face future challenges together.',
'{"weather":{"name":"Sunset","icon":"🌇","description":"Romantic dusk"},"terrain":{"name":"Cafe","icon":"☕","description":"Cozy cafe"},"adventure":{"name":"Persistence","icon":"💪","description":"Fight for love"},"equipment":{"name":"Notebook","icon":"📓","description":"Record stories"}}',
7),

('chapter-rom006-08-en', 'preset-romance-006-en', 'Family Understanding',
'Luna brought Atlas home to meet her parents. Initially, Luna mom was worried, but after talking with Atlas, she saw his sincerity and responsibility. Atlas expressed his love for Luna and his plans for the future. Luna mom finally relaxed and said: "As long as you are happy, we support you." Luna hugged her mom, grateful for her understanding.',
'{"weather":{"name":"Sunny Day","icon":"☀️","description":"Warm sunshine"},"terrain":{"name":"Home","icon":"🏠","description":"Warm home"},"adventure":{"name":"Persistence","icon":"💪","description":"Fight for love"},"equipment":{"name":"Camera","icon":"📷","description":"Capture moments"}}',
8),

('chapter-rom006-09-en', 'preset-romance-006-en', 'Romantic Proposal',
'A year later, Atlas took Luna to the cafe where they first met. The cafe was decorated with flowers and candles, warm and romantic. Atlas knelt on one knee, took out a ring, and said: "Luna, from the moment we met, I knew you were the one I wanted to spend my life with. Will you marry me?" Luna was moved to tears, nodding: "I will." The surrounding customers applauded and blessed them.',
'{"weather":{"name":"Starry Night","icon":"⭐","description":"Beautiful night sky"},"terrain":{"name":"Cafe","icon":"☕","description":"Cozy cafe"},"adventure":{"name":"Proposal","icon":"💍","description":"Romantic proposal"},"equipment":{"name":"Ring","icon":"💍","description":"Symbol of love"}}',
9),

('chapter-rom006-10-en', 'preset-romance-006-en', 'Happy Ending',
'The wedding was held at the beach, with bright sunshine and gentle sea breeze. Luna wore a white wedding dress, looking beautiful. Atlas stood before her, eyes full of love. Under the witness of family and friends, they exchanged vows, promising to love each other forever. Luna mom wiped tears nearby, happy for her daughter. After the ceremony, they walked hand in hand along the beach, watching the sunset. Luna said: "Thank you for making me believe in love." Atlas smiled: "Thank you for helping me find home."',
'{"weather":{"name":"Sunset","icon":"🌇","description":"Romantic dusk"},"terrain":{"name":"Beach","icon":"🏖️","description":"Romantic beach"},"adventure":{"name":"Proposal","icon":"💍","description":"Romantic proposal"},"equipment":{"name":"Ring","icon":"💍","description":"Symbol of love"}}',
10);

-- ============================================
-- 章节数据 - 职场风云：创业逆袭（中文版）
-- ============================================

INSERT INTO chapters (chapter_id, book_id, title, content, selected_cards, order_num) VALUES
('chapter-bus006-01', 'preset-business-006', '裁员的那一天',
'张明站在公司大楼前，手里拿着离职信。作为公司的资深员工，他从未想过自己会被裁员。十年的付出，换来的却是一纸解雇通知。他感到迷茫和无助，不知道未来该何去何从。回到家后，他看着妻子和孩子，心中充满了愧疚。他必须找到新的出路，为了家人，也为了自己。',
'{"weather":{"name":"阴天","icon":"☁️","description":"面临困难"},"terrain":{"name":"办公室","icon":"🏢","description":"奋斗的战场"},"adventure":{"name":"创业","icon":"🚀","description":"开始创业"},"equipment":{"name":"笔记本电脑","icon":"💻","description":"工作必备"}}',
1),

('chapter-bus006-02', 'preset-business-006', '寻找方向',
'失业的日子里，张明开始反思自己的人生。他翻看着过去的笔记，发现自己一直有一个创业的梦想。在咖啡馆里，他遇到了老朋友李华。李华也有创业的想法，两人一拍即合，决定一起创业。他们开始讨论创业的方向，最终决定做一个在线教育平台，帮助更多人学习新技能。',
'{"weather":{"name":"晴天","icon":"☀️","description":"充满希望"},"terrain":{"name":"咖啡馆","icon":"☕","description":"商务洽谈"},"adventure":{"name":"创业","icon":"🚀","description":"开始创业"},"equipment":{"name":"商业计划书","icon":"📋","description":"创业蓝图"}}',
2),

('chapter-bus006-03', 'preset-business-006', '第一笔投资',
'创业初期，资金是最大的问题。张明和李华开始寻找投资人，但一次次被拒绝。他们修改商业计划书，调整产品定位，终于遇到了愿意投资的人。王总是位眼光独到的投资人，他看好在线教育的前景，决定投资他们的项目。拿到第一笔投资的那一刻，张明激动得热泪盈眶。',
'{"weather":{"name":"晴天","icon":"☀️","description":"充满希望"},"terrain":{"name":"投资公司","icon":"🏦","description":"寻找资金"},"adventure":{"name":"融资","icon":"💰","description":"获得投资"},"equipment":{"name":"商业计划书","icon":"📋","description":"创业蓝图"}}',
3),

('chapter-bus006-04', 'preset-business-006', '团队组建',
'有了资金，张明和李华开始组建团队。他们在网上发布招聘信息，面试了许多候选人。最终，他们组建了一支由技术、设计、运营组成的团队。虽然团队规模不大，但每个人都充满热情。他们在租来的小办公室里，开始了创业的征程。',
'{"weather":{"name":"晴天","icon":"☀️","description":"充满希望"},"terrain":{"name":"办公室","icon":"🏢","description":"奋斗的战场"},"adventure":{"name":"创业","icon":"🚀","description":"开始创业"},"equipment":{"name":"名片","icon":"💳","description":"人脉工具"}}',
4),

('chapter-bus006-05', 'preset-business-006', '产品上线',
'经过几个月的开发，产品终于上线了。张明紧张地等待着用户的反馈，但反响平平。下载量很少，用户留存率也不高。团队成员开始有些沮丧，张明鼓励大家不要放弃。他们开始分析用户数据，找出问题所在，准备进行产品迭代。',
'{"weather":{"name":"阴天","icon":"☁️","description":"面临困难"},"terrain":{"name":"办公室","icon":"🏢","description":"奋斗的战场"},"adventure":{"name":"突破","icon":"📈","description":"取得成功"},"equipment":{"name":"笔记本电脑","icon":"💻","description":"工作必备"}}',
5),

('chapter-bus006-06', 'preset-business-006', '分歧与争吵',
'在产品迭代的方向上，张明和李华产生了分歧。张明认为应该专注于内容质量，而李华认为应该先扩大用户规模。两人发生了激烈的争吵，团队气氛变得紧张。王总得知后，召集他们开会，帮助他们化解分歧。王总说："创业路上，分歧是正常的，关键是要找到共同的目标。"',
'{"weather":{"name":"阴天","icon":"☁️","description":"面临困难"},"terrain":{"name":"办公室","icon":"🏢","description":"奋斗的战场"},"adventure":{"name":"坚持","icon":"💪","description":"不忘初心"},"equipment":{"name":"合同","icon":"📄","description":"合作凭证"}}',
6),

('chapter-bus006-07', 'preset-business-006', '反思与和解',
'争吵之后，张明和李华各自冷静下来反思。他们都意识到，创业需要的是合作而不是对抗。张明主动找到李华道歉，李华也承认自己有些急功近利。两人重新坐下来，讨论产品的发展方向，最终达成了共识。他们决定先提升内容质量，同时逐步扩大用户规模。',
'{"weather":{"name":"雨后彩虹","icon":"🌈","description":"转机出现"},"terrain":{"name":"咖啡馆","icon":"☕","description":"商务洽谈"},"adventure":{"name":"坚持","icon":"💪","description":"不忘初心"},"equipment":{"name":"笔记本电脑","icon":"💻","description":"工作必备"}}',
7),

('chapter-bus006-08', 'preset-business-006', '转机出现',
'产品迭代后，用户反馈明显好转。下载量开始上升，用户留存率也提高了。这时，一个创业大赛的机会出现了。张明和李华决定参加，展示他们的产品。在大赛上，他们的产品获得了评委的一致好评，最终获得了冠军。这次胜利为他们带来了更多的关注和投资机会。',
'{"weather":{"name":"雨后彩虹","icon":"🌈","description":"转机出现"},"terrain":{"name":"创业大赛","icon":"🏆","description":"展示机会"},"adventure":{"name":"突破","icon":"📈","description":"取得成功"},"equipment":{"name":"商业计划书","icon":"📋","description":"创业蓝图"}}',
8),

('chapter-bus006-09', 'preset-business-006', '快速发展',
'创业大赛的胜利为公司带来了快速发展。他们搬进了更大的办公室，团队规模也扩大了。产品用户数突破百万，公司估值大幅提升。这时，一家大公司提出收购意向，价格非常诱人。张明和李华面临着一个艰难的选择：是接受收购，还是继续独立发展？',
'{"weather":{"name":"晴天","icon":"☀️","description":"充满希望"},"terrain":{"name":"办公室","icon":"🏢","description":"奋斗的战场"},"adventure":{"name":"突破","icon":"📈","description":"取得成功"},"equipment":{"name":"合同","icon":"📄","description":"合作凭证"}}',
9),

('chapter-bus006-10', 'preset-business-006', '坚持初心',
'经过深思熟虑，张明和李华决定拒绝收购，坚持独立发展。他们相信，只有保持独立，才能真正实现自己的梦想。王总支持他们的决定，并追加了投资。公司继续快速发展，成为了在线教育领域的领军企业。张明站在新办公室的窗前，看着城市的灯火，心中充满了感慨。他知道，这一切都是因为当初没有放弃。',
'{"weather":{"name":"星空","icon":"⭐","description":"展望未来"},"terrain":{"name":"办公室","icon":"🏢","description":"奋斗的战场"},"adventure":{"name":"坚持","icon":"💪","description":"不忘初心"},"equipment":{"name":"名片","icon":"💳","description":"人脉工具"}}',
10);

