INSERT INTO chapters (chapter_id, book_id, title, content, selected_cards, order_num) VALUES
('chapter-bus006-01-en', 'preset-business-006-en', 'The Day of Layoff',
'Max stood before the company building, holding his termination letter. As a senior employee, he never imagined being laid off. Ten years of dedication, exchanged for a dismissal notice. He felt lost and helpless, unsure of his future. Returning home, looking at his wife and children, guilt filled his heart. He had to find a new path—for his family, and for himself.',
'{"weather":{"name":"Cloudy","icon":"☁️","description":"Facing challenges"},"terrain":{"name":"Office","icon":"🏢","description":"Battlefield of work"},"adventure":{"name":"Startup","icon":"🚀","description":"Begin entrepreneurship"},"equipment":{"name":"Laptop","icon":"💻","description":"Work essential"}}',
1),

('chapter-bus006-02-en', 'preset-business-006-en', 'Finding Direction',
'During unemployment, Max reflected on his life. Looking through old notes, he discovered he always had an entrepreneurial dream. At a cafe, he met his old friend Lisa. She also had startup ideas. They clicked immediately and decided to start a business together. They discussed directions and chose to build an online education platform to help people learn new skills.',
'{"weather":{"name":"Sunny","icon":"☀️","description":"Full of hope"},"terrain":{"name":"Cafe","icon":"☕","description":"Business meeting"},"adventure":{"name":"Startup","icon":"🚀","description":"Begin entrepreneurship"},"equipment":{"name":"Business Plan","icon":"📋","description":"Startup blueprint"}}',
2),

('chapter-bus006-03-en', 'preset-business-006-en', 'First Investment',
'In the early days, funding was the biggest challenge. Max and Lisa sought investors but were rejected repeatedly. They revised their business plan, adjusted product positioning, and finally found someone willing to invest. Mr. Wang was a sharp-eyed investor who believed in online education and decided to fund their project. When they received the first investment, Max was moved to tears.',
'{"weather":{"name":"Sunny","icon":"☀️","description":"Full of hope"},"terrain":{"name":"Investment Firm","icon":"🏦","description":"Seeking funding"},"adventure":{"name":"Funding","icon":"💰","description":"Get investment"},"equipment":{"name":"Business Plan","icon":"📋","description":"Startup blueprint"}}',
3),

('chapter-bus006-04-en', 'preset-business-006-en', 'Building the Team',
'With funding secured, Max and Lisa started building their team. They posted job listings online and interviewed many candidates. Finally, they assembled a team of tech, design, and operations people. Though small, everyone was passionate. In their rented small office, they began their startup journey.',
'{"weather":{"name":"Sunny","icon":"☀️","description":"Full of hope"},"terrain":{"name":"Office","icon":"🏢","description":"Battlefield of work"},"adventure":{"name":"Startup","icon":"🚀","description":"Begin entrepreneurship"},"equipment":{"name":"Business Card","icon":"💳","description":"Networking tool"}}',
4),

('chapter-bus006-05-en', 'preset-business-006-en', 'Product Launch',
'After months of development, the product finally launched. Max nervously awaited user feedback, but response was lukewarm. Downloads were few, user retention low. The team grew discouraged, but Max encouraged them not to give up. They began analyzing user data, finding problems, preparing for product iteration.',
'{"weather":{"name":"Cloudy","icon":"☁️","description":"Facing challenges"},"terrain":{"name":"Office","icon":"🏢","description":"Battlefield of work"},"adventure":{"name":"Breakthrough","icon":"📈","description":"Achieve success"},"equipment":{"name":"Laptop","icon":"💻","description":"Work essential"}}',
5),

('chapter-bus006-06-en', 'preset-business-006-en', 'Disagreement and Conflict',
'On product iteration direction, Max and Lisa disagreed. Max believed in focusing on content quality; Lisa thought they should expand user scale first. They argued intensely, and team atmosphere grew tense. Mr. Wang learned of this and called a meeting to help resolve their differences. He said: "Disagreements are normal in startups. The key is finding common goals."',
'{"weather":{"name":"Cloudy","icon":"☁️","description":"Facing challenges"},"terrain":{"name":"Office","icon":"🏢","description":"Battlefield of work"},"adventure":{"name":"Persistence","icon":"💪","description":"Stay true to vision"},"equipment":{"name":"Contract","icon":"📄","description":"Partnership proof"}}',
6),

('chapter-bus006-07-en', 'preset-business-006-en', 'Reflection and Reconciliation',
'After the argument, Max and Lisa each reflected. They realized startups require cooperation, not confrontation. Max approached Lisa to apologize; Lisa admitted she was too impatient. They sat down again, discussed product direction, and reached consensus. They decided to improve content quality first while gradually expanding user scale.',
'{"weather":{"name":"Rainbow","icon":"🌈","description":"Breakthrough comes"},"terrain":{"name":"Cafe","icon":"☕","description":"Business meeting"},"adventure":{"name":"Persistence","icon":"💪","description":"Stay true to vision"},"equipment":{"name":"Laptop","icon":"💻","description":"Work essential"}}',
7),

('chapter-bus006-08-en', 'preset-business-006-en', 'Turning Point',
'After iteration, user feedback improved significantly. Downloads increased, retention rates rose. Then a startup competition opportunity appeared. Max and Lisa decided to participate and showcase their product. At the competition, their product received unanimous praise from judges and won the championship. This victory brought more attention and investment opportunities.',
'{"weather":{"name":"Rainbow","icon":"🌈","description":"Breakthrough comes"},"terrain":{"name":"Startup Contest","icon":"🏆","description":"Showcase opportunity"},"adventure":{"name":"Breakthrough","icon":"📈","description":"Achieve success"},"equipment":{"name":"Business Plan","icon":"📋","description":"Startup blueprint"}}',
8),

('chapter-bus006-09-en', 'preset-business-006-en', 'Rapid Growth',
'The competition victory brought rapid growth. They moved to a larger office, and the team expanded. Product users exceeded one million, company valuation rose dramatically. Then a large company made an acquisition offer at an attractive price. Max and Lisa faced a difficult choice: accept the acquisition, or continue independent development?',
'{"weather":{"name":"Sunny","icon":"☀️","description":"Full of hope"},"terrain":{"name":"Office","icon":"🏢","description":"Battlefield of work"},"adventure":{"name":"Breakthrough","icon":"📈","description":"Achieve success"},"equipment":{"name":"Contract","icon":"📄","description":"Partnership proof"}}',
9),

('chapter-bus006-10-en', 'preset-business-006-en', 'Staying True',
'After careful consideration, Max and Lisa decided to reject the acquisition and continue independent development. They believed only by staying independent could they truly realize their dreams. Mr. Wang supported their decision and added more investment. The company continued rapid growth, becoming a leader in online education. Max stood before the window of his new office, looking at city lights, filled with emotion. He knew all this happened because they never gave up.',
'{"weather":{"name":"Starry Night","icon":"⭐","description":"Looking to future"},"terrain":{"name":"Office","icon":"🏢","description":"Battlefield of work"},"adventure":{"name":"Persistence","icon":"💪","description":"Stay true to vision"},"equipment":{"name":"Business Card","icon":"💳","description":"Networking tool"}}',
10);

